const onWheel = (e) => {
  // ctrl/cmd+wheel is typically browser zoom; don't fight it
  if (e.ctrlKey || e.metaKey) return;

  e.preventDefault();
  const delta = e.deltaY;
  const nextStep = delta > 0 ? -0.08 : 0.08;
  setZoom((z) => clamp(Number((z + nextStep).toFixed(2)), 0.5, 2.5));
};

