onDoubleClick={resetZoom}
onWheel={(e) => {
  // Natural zoom: wheel up zooms in, wheel down zooms out.
  // Use ctrlKey trackpad zoom too.
  e.preventDefault();
  const direction = e.deltaY > 0 ? -1 : 1;
  const step = e.ctrlKey ? 0.06 : 0.1;
  setZoom((z) =>
    clamp(Number((z + direction * step).toFixed(2)), 0.5, 2.5),
  );
}}

function parseHexColor(v, fallback) {
  const raw = String(v || "").trim();
  if (!raw) return fallback;
  const withHash = raw.startsWith("#") ? raw : `#${raw}`;
  const hex = withHash.slice(1);
  if (hex.length !== 6) return fallback;
  const ok = /^[0-9a-fA-F]{6}$/.test(hex);
  return ok ? withHash.toLowerCase() : fallback;
}

